import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limit input size to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input too long!");
            scanner.close();
            return;
        }

        // Use StringBuilder instead of char array to avoid buffer overflow
        StringBuilder sanitizedName = new StringBuilder(name);

        System.out.println("Your name is: " + sanitizedName);

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
